import asyncValue from './asyncValue.js';
export default function asyncFunction(fn, useCallback, arg1, arg2, arg3, arg4, arg5, arg6, ..._args) {
    // biome-ignore lint/complexity/noArguments: Apply arguments
    const callback = arguments[arguments.length - 1];
    const wrapper = (err, result)=>{
        err ? callback(err) : asyncValue(result, callback);
    };
    if (useCallback) {
        // biome-ignore lint/complexity/noArguments: Apply arguments
        switch(arguments.length){
            case 3:
                fn(wrapper);
                return;
            case 4:
                fn(arg1, wrapper);
                return;
            case 5:
                fn(arg1, arg2, wrapper);
                return;
            case 6:
                fn(arg1, arg2, arg3, wrapper);
                return;
            case 7:
                fn(arg1, arg2, arg3, arg4, wrapper);
                return;
            case 8:
                fn(arg1, arg2, arg3, arg4, arg5, wrapper);
                return;
            case 9:
                fn(arg1, arg2, arg3, arg4, arg5, arg6, wrapper);
                return;
            default:
                {
                    // biome-ignore lint/complexity/noArguments: Apply arguments
                    const args = Array.prototype.slice.call(arguments, 2);
                    args[args.length - 1] = wrapper; // replace callback with wrapper
                    fn.apply(null, args);
                    return;
                }
        }
    }
    // biome-ignore lint/complexity/noArguments: Apply arguments
    switch(arguments.length){
        case 3:
            wrapper(null, fn());
            return;
        case 4:
            wrapper(null, fn(arg1));
            return;
        case 5:
            wrapper(null, fn(arg1, arg2));
            return;
        case 6:
            wrapper(null, fn(arg1, arg2, arg3));
            return;
        case 7:
            wrapper(null, fn(arg1, arg2, arg3, arg4));
            return;
        case 8:
            wrapper(null, fn(arg1, arg2, arg3, arg4, arg5));
            return;
        case 9:
            wrapper(null, fn(arg1, arg2, arg3, arg4, arg5, arg6));
            return;
        default:
            {
                // biome-ignore lint/complexity/noArguments: Apply arguments
                const args = Array.prototype.slice.call(arguments, 2);
                args.pop(); // remove callback
                wrapper(null, fn.apply(null, args));
                return;
            }
    }
}
